{"code": "import json
import re

# Load the full result from file
result_file = locals()['var_functions.query_db:22']
if isinstance(result_file, str) and result_file.endswith('.json'):
    with open(result_file, 'r') as f:
        rl = json.load(f)
else:
    rl = locals()['var_functions.query_db:22']

# Extract female BRCA patients
female_brca_patients = []
excluded_reliability = 0
excluded_histology = 0

for record in rl:
    desc = record['Patient_description']
    hist_type = record['histological_type']
    patient_id = record['patient_id']

    # Extract barcode
    barcode_match = re.search(r'(TCGA-\w+-\w+)', desc)
    if barcode_match:
        barcode = barcode_match.group(1)

        # Check if female (by looking for FEMALE in description)
        if 'FEMALE' in desc:
            # Check for known histological type (exclude 'Other specify' and missing)
            if hist_type and hist_type != 'Other  specify' and hist_type != '[Not Available]':
                # Extract cancer type from description
                if 'Breast invasive carcinoma' in desc or 'BRCA' in barcode:
                    female_brca_patients.append({
                        'barcode': barcode,
                        'histological_type': hist_type,
                        'patient_id': patient_id,
                        'description': desc
                    })
            else:
                excluded_histology += 1

print('__RESULT__:')
print(json.dumps({
    'total_records_processed': len(rl),
    'female_brca_patients': len(female_brca_patients),
    'unique_histological_types': len(set([p['histological_type'] for p in female_brca_patients])),
    'histology_distribution': {ht: sum(1 for p in female_brca_patients if p['histological_type'] == ht) 
                               for ht in set([p['histological_type'] for p in female_brca_patients])},
    'patient_ids': [p['patient_id'] for p in female_brca_patients[:10]]
}))"}

