import re

# Load the full result from file
result_file = locals()['var_functions.query_db:22']
if isinstance(result_file, str) and result_file.endswith('.json'):
    with open(result_file, 'r') as f:
        rl = json.load(f)
else:
    rl = locals()['var_functions.query_db:22']

# Extract all female BRCA patients with known histology
female_brca_data = []

for record in rl:
    desc = record['Patient_description']
    hist_type = record['histological_type']
    patient_id = record['patient_id']

    # Extract barcode
    barcode_match = re.search(r'(TCGA-\w+-\w+)', desc)
    if barcode_match:
        barcode = barcode_match.group(1)

        # Check if female and has known histology
        if 'FEMALE' in desc:
            if hist_type and hist_type != 'Other  specify' and hist_type != '[Not Available]' and hist_type != 'None':
                if 'Breast invasive carcinoma' in desc:
                    female_brca_data.append({
                        'barcode': barcode,
                        'histological_type': hist_type
                    })

# Create a mapping of barcodes to histological types
barcode_to_histology = {item['barcode']: item['histological_type'] for item in female_brca_data}

print('__RESULT__:')
print(json.dumps({
    'total_female_brca': len(female_brca_data),
    'unique_histologies': len(set([p['histological_type'] for p in female_brca_data])),
    'barcode_to_histology_count': len(barcode_to_histology),
    'sample_entries': female_brca_data[:5]
}))"}

