# Extract female BRCA patients with known histology
female_brca_patients = []
for record in clinical_data:
    desc = record['Patient_description']
    hist_type = record.get('histological_type', '')

    # Extract barcode
    barcode_match = re.search(r'(TCGA-\w+-\w+)', desc)
    if barcode_match:
        barcode = barcode_match.group(1)

        # Check if female and has known histology
        if 'FEMALE' in desc and hist_type and hist_type not in ['Other  specify', '[Not Available]', 'None', '']:
            if 'Breast invasive carcinoma' in desc:
                female_brca_patients.append({
                    'barcode': barcode,
                    'histological_type': hist_type
                })

# Create mappings
barcode_to_histology = {p['barcode']: p['histological_type'] for p in female_brca_patients}
all_barcodes = set(barcode_to_histology.keys())

# Get reliable CDH1 mutations (FILTER='PASS')
reliable_cdh1_mutations = set()
for record in mutation_data:
    barcode = record['ParticipantBarcode']
    filter_status = record['FILTER']

    # Only consider PASS mutations within our female BRCA cohort
    if filter_status == 'PASS' and barcode in all_barcodes:
        reliable_cdh1_mutations.add(barcode)

# Build contingency table: histological type vs CDH1 mutation status
contingency_table = {}
histology_counts = {}
for ht in set(barcode_to_histology.values()):
    contingency_table[ht] = {'CDH1_mutated': 0, 'CDH1_wildtype': 0}
    histology_counts[ht] = 0

# Count patients by histology and CDH1 status
for barcode, hist_type in barcode_to_histology.items():
    histology_counts[hist_type] += 1
    if barcode in reliable_cdh1_mutations:
        contingency_table[hist_type]['CDH1_mutated'] += 1
    else:
        contingency_table[hist_type]['CDH1_wildtype'] += 1

# Apply exclusion criteria: exclude categories with marginal totals <= 10
# Calculate marginal totals (row totals and column totals)
row_totals = {ht: sum(contingency_table[ht].values()) for ht in contingency_table}
column_totals = {
    'CDH1_mutated': sum(contingency_table[ht]['CDH1_mutated'] for ht in contingency_table),
    'CDH1_wildtype': sum(contingency_table[ht]['CDH1_wildtype'] for ht in contingency_table)
}

# Filter out histological types with row totals <= 10
filtered_contingency = {}
for ht, counts in contingency_table.items():
    if row_totals[ht] > 10:  # Only include histologies with more than 10 patients
        filtered_contingency[ht] = counts

# Calculate grand total (should be same as sum of column totals)
grand_total = sum(column_totals.values())

print('__RESULT__:')
print(json.dumps({
    'total_patients': len(female_brca_patients),
    'cdh1_mutated_in_cohort': len(reliable_cdh1_mutations),
    'contingency_table': contingency_table,
    'row_totals': row_totals,
    'column_totals': column_totals,
    'grand_total': grand_total,
    'filtered_contingency': filtered_contingency,
    'filtered_histologies': len(filtered_contingency)
}, indent=2))"}

